function solveTurnstileMin({ url, proxy, siteKey }) {
  return new Promise(async (resolve, reject) => {
    if (!url) return reject("Missing url parameter");
    if (!siteKey) return reject("Missing siteKey parameter");

    const context = await global.browser
      .createBrowserContext({
        proxyServer: proxy
          ? `http://${proxy.host}:${proxy.port}`
          : undefined,
      })
      .catch(() => null);

    if (!context) return reject("Failed to create browser context");

    let isResolved = false;

    const cl = setTimeout(async () => {
      if (!isResolved) {
        await context.close().catch(() => {});
        reject("Timeout Error");
      }
    }, global.timeOut || 60000);

    try {
      const page = await context.newPage();

      if (proxy?.username && proxy?.password) {
        await page.authenticate({
          username: proxy.username,
          password: proxy.password,
        });
      }

      await page.setRequestInterception(true);

      page.on("request", async (request) => {
        try {
          if (
            [url, url + "/"].includes(request.url()) &&
            request.resourceType() === "document"
          ) {
            await request.respond({
              status: 200,
              contentType: "text/html",
              body: require("fs")
                .readFileSync("./src/data/fakePage.html", "utf8")
                .replace(/<site-key>/g, siteKey),
            });
          } else {
            await request.continue();
          }
        } catch {}
      });

      await page.goto(url, {
        waitUntil: "domcontentloaded",
      });

      await page.waitForSelector('[name="cf-response"]', {
        timeout: 60000,
      });

      const result = await page.evaluate(() => {
        return {
          token:
            document.querySelector('[name="cf-response"]')?.value || null,
          userAgent: navigator.userAgent,
        };
      });

      isResolved = true;
      clearTimeout(cl);

      await context.close();

      if (!result.token || result.token.length < 10) {
        return reject("Failed to get token");
      }

      resolve({
        token: result.token,
        userAgent: result.userAgent,
      });
    } catch (e) {
      if (!isResolved) {
        clearTimeout(cl);
        await context.close().catch(() => {});
        reject(e.message || String(e));
      }
    }
  });
}

module.exports = solveTurnstileMin;
